  1→/**
  2→ * Pipeline API Client
  3→ *
  4→ * TypeScript client for Pipeline API with fetch wrapper.
  5→ * Provides typed methods for listing pipelines and fetching pipeline details.
  6→ */
  7→
  8→import type {
  9→  PipelineData,
 10→  DealStageData,
 11→  ApiListResponse,
 12→  ApiResponse,
 13→  ApiClientConfig,
 14→} from './types';
 15→import { ApiClientError, parseApiError, parseJson } from './shared';
 16→
 17→export { ApiClientError } from './shared';
 18→
 19→/**
 20→ * Pipeline with its stages included
 21→ */
 22→export interface PipelineWithStages extends PipelineData {
 23→  DealStage: DealStageData[];
 24→}
 25→
 26→const DEFAULT_BASE_URL = '/api';
 27→
 28→export class PipelineApiClient {
 29→  private baseUrl: string;
 30→  private fetchFn: typeof globalThis.fetch;
 31→  private defaultHeaders: Record<string, string>;
 32→
 33→  constructor(config: ApiClientConfig = {}) {
 34→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 35→    this.fetchFn = config.fetch ?? fetch;
 36→    this.defaultHeaders = {
 37→      'Content-Type': 'application/json',
 38→      ...config.headers,
 39→    };
 40→  }
 41→
 42→  private url(path: string, params?: Record<string, string | undefined>): string {
 43→    const fullUrl = `${this.baseUrl}${path}`;
 44→
 45→    if (params) {
 46→      const searchParams = new URLSearchParams();
 47→      for (const [key, value] of Object.entries(params)) {
 48→        if (value !== undefined) {
 49→          searchParams.append(key, value);
 50→        }
 51→      }
 52→      const queryString = searchParams.toString();
 53→      if (queryString) {
 54→        return `${fullUrl}?${queryString}`;
 55→      }
 56→    }
 57→
 58→    return fullUrl;
 59→  }
 60→
 61→  /**
 62→   * GET /api/pipelines
 63→   *
 64→   * List all active pipelines.
 65→   */
 66→  async getPipelines(): Promise<ApiListResponse<PipelineData>> {
 67→    const response = await this.fetchFn(this.url('/pipelines'), {
 68→      headers: this.defaultHeaders,
 69→    });
 70→
 71→    if (!response.ok) {
 72→      return parseApiError(response);
 73→    }
 74→
 75→    return parseJson<ApiListResponse<PipelineData>>(response);
 76→  }
 77→
 78→  /**
 79→   * GET /api/pipelines/[id]
 80→   *
 81→   * Fetch a single pipeline with its stages, sorted by order.
 82→   *
 83→   * @throws ApiClientError with 400 if id is empty
 84→   * @throws ApiClientError with 404 if not found
 85→   */
 86→  async getPipeline(id: string): Promise<ApiResponse<PipelineWithStages>> {
 87→    if (!id) {
 88→      throw new ApiClientError(400, 'Validation failed', 'id is required');
 89→    }
 90→
 91→    const response = await this.fetchFn(this.url(`/pipelines/${id}`), {
 92→      headers: this.defaultHeaders,
 93→    });
 94→
 95→    if (!response.ok) {
 96→      return parseApiError(response);
 97→    }
 98→
 99→    return parseJson<ApiResponse<PipelineWithStages>>(response);
100→  }
101→}
102→
103→/**
104→ * Default singleton instance
105→ */
106→export const pipelinesApi = new PipelineApiClient();
107→
108→/**
109→ * Convenience exports
110→ */
111→export const { getPipelines, getPipeline } = pipelinesApi;
112→
113→export default pipelinesApi;
114→

